.Search input {
  width: 500px;
  height: 40px;
  border-radius: 20px;
  border: none;
  padding-left: 20px;
  font-size: 14pt;
  box-shadow: 2px 2px 2px rgba(0, 0, 0, 0.1);
  background-color: rgba(187, 187, 187, 0.2); 
  color: #bbbbbb; 
  outline: none;
  transition: all 0.3s ease;
}

.Search input::placeholder {
  color: #bbbbbb;
  opacity: 1;
}

.Search input:focus {
  border: solid 1px white;
  box-shadow: 0 0 0 1px white;
  background-color: transparent;
  color: white;
}
